"use client";

import { useEffect, useMemo, useState } from "react";
import Link from "next/link";
import { useRouter } from "next/navigation";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import {
  Calendar,
  CheckCircle2,
  ChevronLeft,
  ChevronRight,
  Clock,
  MapPin,
  RefreshCw,
  ScrollText,
} from "lucide-react";

const dayNames = ["Sun", "Mon", "Tue", "Wed", "Thu", "Fri", "Sat"];

type BookingStatus = "pending" | "confirmed" | "completed" | "cancelled";

type Booking = {
  id: string;
  email: string;
  service: string;
  date: string;
  time: string;
  status: BookingStatus;
  address: string;
  amount: number;
  instructions: string;
};

const bookingsMock: Booking[] = [
  {
    id: "BK001",
    email: "john@example.com",
    service: "Deep Cleaning",
    date: "2024-11-18",
    time: "09:00 AM",
    status: "confirmed",
    address: "123 Main St, Chicago, IL",
    amount: 250,
    instructions: "Focus on the kitchen appliances",
  },
  {
    id: "BK002",
    email: "john@example.com",
    service: "Standard Cleaning",
    date: "2024-11-05",
    time: "02:00 PM",
    status: "completed",
    address: "123 Main St, Chicago, IL",
    amount: 120,
    instructions: "Leave extra towels in the bathroom",
  },
  {
    id: "BK003",
    email: "jane@example.com",
    service: "Move In/Out Cleaning",
    date: "2024-11-22",
    time: "11:30 AM",
    status: "pending",
    address: "456 Oak Ave, Chicago, IL",
    amount: 320,
    instructions: "Bring carpet shampoo machine",
  },
  {
    id: "BK004",
    email: "jane@example.com",
    service: "Carpet Cleaning",
    date: "2024-10-10",
    time: "10:30 AM",
    status: "cancelled",
    address: "456 Oak Ave, Chicago, IL",
    amount: 180,
    instructions: "Customer will provide parking pass",
  },
];

const statusCopy: Record<BookingStatus, { label: string; tone: string }> = {
  pending: {
    label: "Pending",
    tone: "bg-yellow-100 text-yellow-700 dark:bg-yellow-900/20 dark:text-yellow-300",
  },
  confirmed: {
    label: "Confirmed",
    tone: "bg-blue-100 text-blue-700 dark:bg-blue-900/20 dark:text-blue-300",
  },
  completed: {
    label: "Completed",
    tone: "bg-green-100 text-green-700 dark:bg-green-900/20 dark:text-green-300",
  },
  cancelled: {
    label: "Cancelled",
    tone: "bg-red-100 text-red-700 dark:bg-red-900/20 dark:text-red-300",
  },
};

const getStatusIcon = (status: BookingStatus) => {
  switch (status) {
    case "pending":
      return Clock;
    case "confirmed":
      return RefreshCw;
    case "completed":
      return CheckCircle2;
    case "cancelled":
      return ScrollText;
    default:
      return Clock;
  }
};

const CustomerDashboard = () => {
  const router = useRouter();
  const [customerName, setCustomerName] = useState("Customer");
  const [customerEmail, setCustomerEmail] = useState<string | null>(null);
  const [viewMode, setViewMode] = useState<"calendar" | "list">("calendar");
  const [calendarDate, setCalendarDate] = useState(() => new Date());

  useEffect(() => {
    if (typeof window === "undefined") return;

    const storedName = localStorage.getItem("customerName") || "Customer";
    const storedEmail = localStorage.getItem("customerEmail");

    setCustomerName(storedName.replace(/\b\w/g, (char) => char.toUpperCase()));
    setCustomerEmail(storedEmail);
  }, []);

  const bookings = useMemo<Booking[]>(() => {
    if (!customerEmail) return [];
    return bookingsMock.filter((booking) => booking.email === customerEmail);
  }, [customerEmail]);

  const totals = useMemo(() => {
    const today = new Date();
    const startOfToday = new Date(today.toDateString());

    const upcoming = bookings.filter((booking) => {
      const bookingDate = new Date(booking.date);
      return ["pending", "confirmed"].includes(booking.status) && bookingDate >= startOfToday;
    });

    const completed = bookings.filter((booking) => booking.status === "completed");
    const lifetimeSpend = bookings.reduce((sum, booking) => sum + booking.amount, 0);

    return {
      totalBookings: bookings.length,
      upcomingCount: upcoming.length,
      completedCount: completed.length,
      lifetimeSpend,
      upcoming,
    };
  }, [bookings]);

  const upcomingByDate = useMemo(() => {
    const map = new Map<string, Booking[]>();
    totals.upcoming.forEach((booking) => {
      const existing = map.get(booking.date) ?? [];
      map.set(booking.date, [...existing, booking]);
    });
    return map;
  }, [totals.upcoming]);

  const calendarCells = useMemo(() => {
    const year = calendarDate.getFullYear();
    const month = calendarDate.getMonth();
    const firstDay = new Date(year, month, 1).getDay();
    const daysInMonth = new Date(year, month + 1, 0).getDate();

    const formatDateKey = (date: Date) =>
      `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, "0")}-${String(date.getDate()).padStart(2, "0")}`;

    const cells: ({ date: Date; dateKey: string; bookings: Booking[] } | null)[] = [];

    for (let i = 0; i < firstDay; i++) {
      cells.push(null);
    }

    for (let day = 1; day <= daysInMonth; day++) {
      const date = new Date(year, month, day);
      const dateKey = formatDateKey(date);
      cells.push({ date, dateKey, bookings: upcomingByDate.get(dateKey) ?? [] });
    }

    while (cells.length % 7 !== 0) {
      cells.push(null);
    }

    return cells;
  }, [calendarDate, upcomingByDate]);

  const calendarLabel = calendarDate.toLocaleDateString("en-US", { month: "long", year: "numeric" });

  const adjustMonth = (direction: "prev" | "next") => {
    setCalendarDate((prev) => new Date(prev.getFullYear(), prev.getMonth() + (direction === "next" ? 1 : -1), 1));
  };

  const StatusBadge = ({ status }: { status: BookingStatus }) => {
    const Icon = getStatusIcon(status);
    return (
      <Badge className={`inline-flex items-center gap-1 px-2.5 py-1 ${statusCopy[status].tone}`}>
        <Icon className="h-3.5 w-3.5" />
        {statusCopy[status].label}
      </Badge>
    );
  };

  return (
    <div className="space-y-10">
      <section className="space-y-8">
        <div className="grid gap-4 sm:grid-cols-2 lg:grid-cols-4">
          <Card>
            <CardHeader className="pb-2">
              <CardTitle className="text-sm text-muted-foreground">Total Bookings</CardTitle>
            </CardHeader>
            <CardContent>
              <p className="text-2xl font-bold">{totals.totalBookings}</p>
              <p className="text-xs text-muted-foreground mt-1">
                Across your entire Orbit Booking history.
              </p>
            </CardContent>
          </Card>
          <Card>
            <CardHeader className="pb-2">
              <CardTitle className="text-sm text-muted-foreground">Upcoming Visits</CardTitle>
            </CardHeader>
            <CardContent>
              <p className="text-2xl font-bold">{totals.upcomingCount}</p>
              <p className="text-xs text-muted-foreground mt-1">
                Pending or confirmed services scheduled next.
              </p>
            </CardContent>
          </Card>
          <Card>
            <CardHeader className="pb-2">
              <CardTitle className="text-sm text-muted-foreground">Completed Services</CardTitle>
            </CardHeader>
            <CardContent>
              <p className="text-2xl font-bold">{totals.completedCount}</p>
              <p className="text-xs text-muted-foreground mt-1">
                Thank you for trusting our team!
              </p>
            </CardContent>
          </Card>
          <Card>
            <CardHeader className="pb-2">
              <CardTitle className="text-sm text-muted-foreground">Lifetime Spend</CardTitle>
            </CardHeader>
            <CardContent>
              <p className="text-2xl font-bold">${totals.lifetimeSpend.toFixed(2)}</p>
              <p className="text-xs text-muted-foreground mt-1">
                Based on invoices for completed services.
              </p>
            </CardContent>
          </Card>
        </div>

        <Card>
          <CardHeader>
            <div className="flex flex-col gap-4 md:flex-row md:items-center md:justify-between">
              <div>
                <CardTitle>Upcoming Appointments</CardTitle>
                <p className="text-sm text-muted-foreground">
                  Switch between calendar and list views to keep track of what's coming next.
                </p>
              </div>
              <div className="flex flex-col gap-2 sm:flex-row sm:items-center sm:justify-end">
                <div className="inline-flex items-center rounded-lg border border-border bg-muted/30 p-1">
                  <Button
                    size="sm"
                    variant={viewMode === "calendar" ? "default" : "ghost"}
                    className="rounded-md"
                    onClick={() => setViewMode("calendar")}
                  >
                    Calendar
                  </Button>
                  <Button
                    size="sm"
                    variant={viewMode === "list" ? "default" : "ghost"}
                    className="rounded-md"
                    onClick={() => setViewMode("list")}
                  >
                    List
                  </Button>
                </div>
                <Button size="sm" variant="outline" onClick={() => router.push("/book-now")}>
                  Schedule Cleaning
                </Button>
              </div>
            </div>
          </CardHeader>
          <CardContent>
            {totals.upcomingCount === 0 ? (
              <div className="text-center py-10 space-y-3">
                <Clock className="h-10 w-10 mx-auto text-muted-foreground" />
                <p className="text-sm text-muted-foreground">
                  You're all caught up. Schedule your next cleaning when you're ready.
                </p>
                <Button asChild>
                  <Link href="/book-now">Book your next visit</Link>
                </Button>
              </div>
            ) : viewMode === "calendar" ? (
              <div className="space-y-4">
                <div className="flex flex-wrap items-center justify-between gap-3">
                  <div className="flex items-center gap-2">
                    <Button variant="ghost" size="icon" onClick={() => adjustMonth("prev")} aria-label="Previous month">
                      <ChevronLeft className="h-4 w-4" />
                    </Button>
                    <span className="text-sm font-semibold text-foreground">{calendarLabel}</span>
                    <Button variant="ghost" size="icon" onClick={() => adjustMonth("next")} aria-label="Next month">
                      <ChevronRight className="h-4 w-4" />
                    </Button>
                  </div>
                  <p className="text-xs text-muted-foreground">
                    Showing {totals.upcomingCount} upcoming appointment{totals.upcomingCount > 1 ? "s" : ""}
                  </p>
                </div>
                <div className="grid grid-cols-7 text-xs font-semibold text-muted-foreground">
                  {dayNames.map((day) => (
                    <div key={day} className="py-2 text-center">
                      {day}
                    </div>
                  ))}
                </div>
                <div className="grid grid-cols-7 gap-2">
                  {calendarCells.map((cell, index) => {
                    if (!cell) {
                      return <div key={`empty-${index}`} className="rounded-xl border border-transparent p-2 min-h-[110px]" />;
                    }

                    const { date, dateKey, bookings } = cell;

                    return (
                      <div
                        key={dateKey}
                        className={`rounded-xl border p-2 min-h-[110px] flex flex-col gap-2 ${
                          bookings.length > 0 ? "border-primary bg-primary/5" : "border-border"
                        }`}
                      >
                        <div className="flex items-center justify-between text-xs font-medium text-foreground">
                          <span>{date.getDate()}</span>
                          {bookings.length > 0 && (
                            <Badge variant="secondary" className="text-[10px] font-semibold px-2 py-0">
                              {bookings.length}
                            </Badge>
                          )}
                        </div>
                        <div className="space-y-1 text-[11px]">
                          {bookings.slice(0, 2).map((booking) => (
                            <div key={booking.id} className="rounded-md border border-border/60 bg-background px-2 py-1 shadow-sm">
                              <p className="font-medium text-foreground">{booking.service}</p>
                              <p className="text-muted-foreground">{booking.time}</p>
                            </div>
                          ))}
                          {bookings.length > 2 && (
                            <p className="text-[11px] text-muted-foreground">+{bookings.length - 2} more</p>
                          )}
                        </div>
                      </div>
                    );
                  })}
                </div>
              </div>
            ) : (
              <div className="space-y-4">
                {totals.upcoming.map((booking) => (
                  <div
                    key={booking.id}
                    className="border border-border rounded-xl p-4 hover:bg-muted/40 transition-colors"
                  >
                    <div className="flex flex-col gap-3 md:flex-row md:items-center md:justify-between">
                      <div className="space-y-1">
                        <div className="flex items-center gap-2">
                          <Calendar className="h-4 w-4 text-muted-foreground" />
                          <h3 className="text-base font-semibold text-foreground">{booking.service}</h3>
                        </div>
                        <p className="text-sm text-muted-foreground">
                          {booking.date} • {booking.time}
                        </p>
                      </div>
                      <StatusBadge status={booking.status} />
                    </div>

                    <div className="mt-4 grid gap-3 sm:grid-cols-2">
                      <div className="flex items-center gap-2 text-sm text-muted-foreground">
                        <MapPin className="h-4 w-4" />
                        <span>{booking.address}</span>
                      </div>
                      <div className="text-sm">
                        <p className="text-muted-foreground">Service notes</p>
                        <p className="text-foreground font-medium">{booking.instructions || "—"}</p>
                      </div>
                      <div className="text-sm">
                        <p className="text-muted-foreground">Booking ID</p>
                        <p className="font-medium text-foreground">{booking.id}</p>
                      </div>
                      <div className="text-right sm:text-left">
                        <p className="text-sm text-muted-foreground">Amount</p>
                        <p className="text-xl font-semibold">${booking.amount.toFixed(2)}</p>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </CardContent>
        </Card>
      </section>
    </div>
  );
};

export default function CustomerDashboardPage() {
  return <CustomerDashboard />;
}
